import { getProductAssetEntry } from './productAssets.js'

const productPlaceholder = '/images/placeholders/product-placeholder.svg'
const buildingProductPlaceholder = '/images/placeholders/product-building-placeholder.svg'
const plumbingProductPlaceholder = '/images/placeholders/product-plumbing-placeholder.svg'

function imageFor(titleKg, slug) {
  const asset = getProductAssetEntry(slug)
  const src = asset?.main || `${productPlaceholder}`

  return [
    {
      src,
      alt: asset?.altKg || `${titleKg} - StroyRayon товар сүрөтү`,
      width: 900,
      height: 675,
      type: asset?.available ? 'packshot' : 'planned',
      fallbackSrc: asset?.fallback || productPlaceholder,
      expectedSrc: asset?.main,
      futureSrc: asset?.futureMain || asset?.main || `/images/products/${slug}/main.webp`,
    },
  ]
}

