function applyStage5CEngineeringContent(data) {
  const content = stage5CEngineeringContent[data.slug]
  if (!content) return data
  const { replaceSpecifications, ...contentData } = content

  return {
    ...data,
    ...contentData,
    specificationsKg: replaceSpecifications
      ? contentData.specificationsKg
      : {
          ...(data.specificationsKg || data.specs || {}),
          ...(contentData.specificationsKg || {}),
        },
    specificationsRu: replaceSpecifications
      ? contentData.specificationsRu
      : {
          ...(data.specificationsRu || data.specsRu || {}),
          ...(contentData.specificationsRu || {}),
        },
    aliases: [...new Set([...(data.aliases || []), ...(contentData.aliases || [])].filter(Boolean))],
    relatedProductIds: contentData.relatedProductIds || data.relatedProductIds,
  }
}

function stage5DSpecs({
  brand,
  typeKg,
  typeRu,
  materialKg,
  materialRu,
  size,
  purposeKg,
  purposeRu,
  areaKg,
  areaRu,
  connectionKg,
  connectionRu,
  serviceKg,
  serviceRu,
  unitKg = 'даана',
  unitRu = 'шт.',
  minOrderKg = '1 даана',
  minOrderRu = '1 шт.',
}) {
  return {
    kg: {
      Бренд: brand,
      'Товар түрү': typeKg,
      Материал: materialKg,
      'Өлчөм / параметр': size,
      Максаты: purposeKg,
      'Колдонуу аймагы': areaKg,
      'Туташтыруу / шайкештик': connectionKg,
      'Тейлөө жана тандоо': serviceKg,
      'Сатуу бирдиги': unitKg,
      'Минималдуу заказ': minOrderKg,
    },
    ru: {
      Бренд: brand,
      'Тип товара': typeRu,
      Материал: materialRu,
      'Размер / параметр': size,
      Назначение: purposeRu,
      'Область применения': areaRu,
      'Подключение / совместимость': connectionRu,
      'Обслуживание и подбор': serviceRu,
      'Единица продажи': unitRu,
      'Минимальный заказ': minOrderRu,
    },
  }
}

function makeStage5DContent(item) {
  const specs = stage5DSpecs(item)
  return makeStage5BItem({
    titleKg: item.titleKg,
    titleRu: item.titleRu,
    productType: item.productType,
    productTypeRu: item.productTypeRu,
    minOrder: item.minOrder || '1 даана',
    minOrderRu: item.minOrderRu || '1 шт.',
    pack: item.pack || 'даана менен берилет',
    packRu: item.packRu || 'поштучно',
    shortKg: item.shortKg,
    shortRu: item.shortRu,
    fullKg: item.fullKg,
    fullRu: item.fullRu,
    specificationsKg: specs.kg,
    specificationsRu: specs.ru,
    applicationKg: item.applicationKg,
    applicationRu: item.applicationRu,
    benefitsKg: item.benefitsKg,
    benefitsRu: item.benefitsRu,
    instructionsKg: item.instructionsKg,
    instructionsRu: item.instructionsRu,
    faqKg: item.faqKg,
    faqRu: item.faqRu,
    seoTitleKg: item.seoTitleKg,
    seoTitleRu: item.seoTitleRu,
    seoDescriptionKg: item.seoDescriptionKg,
    seoDescriptionRu: item.seoDescriptionRu,
    aliasesKg: item.aliasesKg,
    aliasesRu: item.aliasesRu,
    relatedProductIds: item.relatedProductIds,
  })
}

