function applyStage5DEngineeringContent(data) {
  const content = stage5DEngineeringContent[data.slug]
  if (!content) return data
  const { replaceSpecifications, ...contentData } = content

  return {
    ...data,
    ...contentData,
    specificationsKg: replaceSpecifications
      ? contentData.specificationsKg
      : {
          ...(data.specificationsKg || data.specs || {}),
          ...(contentData.specificationsKg || {}),
        },
    specificationsRu: replaceSpecifications
      ? contentData.specificationsRu
      : {
          ...(data.specificationsRu || data.specsRu || {}),
          ...(contentData.specificationsRu || {}),
        },
    aliases: [...new Set([...(data.aliases || []), ...(contentData.aliases || [])].filter(Boolean))],
    relatedProductIds: contentData.relatedProductIds || data.relatedProductIds,
  }
}

