    seoDescriptionKg: item.seoDescriptionKg,
    seoDescriptionRu: item.seoDescriptionRu,
    aliasesKg: item.aliasesKg,
    aliasesRu: item.aliasesRu,
    relatedProductIds: item.relatedProductIds,
