    shortDescriptionKg: item.shortKg,
    shortDescriptionRu: item.shortRu,
    fullDescriptionKg: item.fullKg,
    fullDescriptionRu: item.fullRu,
    specificationsKg: specs.kg,
    specificationsRu: specs.ru,
    applicationKg: item.applicationKg,
    applicationRu: item.applicationRu,
    benefitsKg: item.benefitsKg,
    benefitsRu: item.benefitsRu,
    instructionsKg: item.instructionsKg || toolSafetyInstructionsKg,
    instructionsRu: item.instructionsRu || toolSafetyInstructionsRu,
    faqKg: item.faqKg,
    faqRu: item.faqRu,
    seoTitleKg: item.seoTitleKg,
    seoTitleRu: item.seoTitleRu,
    seoDescriptionKg: item.seoDescriptionKg,
    seoDescriptionRu: item.seoDescriptionRu,
    aliasesKg: item.aliasesKg,
    aliasesRu: item.aliasesRu,
    relatedProductIds: item.relatedProductIds,
