function stage11VentSpecs({
  brand = 'VentPro',
  typeKg,
  typeRu,
  materialKg = 'Пластик/PVC, партия боюнча такталат',
  materialRu = 'Пластик/PVC, уточняется по партии',
  size,
  purposeKg,
  purposeRu,
  areaKg,
  areaRu,
  formKg,
  formRu,
  colorKg,
  colorRu,
  mountingKg,
  mountingRu,
  compatibilityKg,
  compatibilityRu,
  unitKg = 'даана',
  unitRu = 'шт.',
  minOrderKg = '1 даана',
  minOrderRu = '1 шт.',
}) {
  const kg = {
    Бренд: brand,
    'Товар түрү': typeKg,
    Материал: materialKg,
    'Размер / диаметр': size,
    Максаты: purposeKg,
    'Колдонуу аймагы': areaKg,
    'Сатуу бирдиги': unitKg,
    'Минималдуу заказ': minOrderKg,
  }
  const ru = {
    Бренд: brand,
    'Тип товара': typeRu,
    Материал: materialRu,
    'Размер / диаметр': size,
    Назначение: purposeRu,
    'Область применения': areaRu,
    'Единица продажи': unitRu,
    'Минимальный заказ': minOrderRu,
  }

  if (formKg) kg.Форма = formKg
  if (formRu) ru.Форма = formRu
  if (colorKg) kg.Түсү = colorKg
  if (colorRu) ru.Цвет = colorRu
  if (mountingKg) kg.Монтаж = mountingKg
  if (mountingRu) ru.Монтаж = mountingRu
  if (compatibilityKg) kg.Шайкештик = compatibilityKg
  if (compatibilityRu) ru.Совместимость = compatibilityRu

  return { kg, ru }
}

