function applyStage12WarmFloorContent(data) {
  const content = stage12WarmFloorContent[data.slug]
  if (!content) return data

  return {
    ...data,
    ...content,
    specificationsKg: {
      ...(data.specificationsKg || data.specs || {}),
      ...(content.specificationsKg || {}),
    },
    specificationsRu: {
      ...(data.specificationsRu || data.specsRu || {}),
      ...(content.specificationsRu || {}),
    },
    aliases: [...new Set([...(data.aliases || []), ...(content.aliases || [])].filter(Boolean))],
    aliasesKg: [...new Set([...(data.aliasesKg || []), ...(content.aliasesKg || [])].filter(Boolean))],
    aliasesRu: [...new Set([...(data.aliasesRu || []), ...(content.aliasesRu || [])].filter(Boolean))],
    relatedProductIds: content.relatedProductIds || data.relatedProductIds,
  }
}

