function stage14ASpecs(item) {
  return {
    kg: {
      Бренд: item.brand,
      'Товар түрү': item.typeKg,
      Багыты: item.purposeKg,
      'Колдонуу аймагы': item.areaKg,
      'Основа/курамы': item.baseKg,
      'Салмак/фасовка': item.packKg,
      'Ички/сырткы иштер': item.workZoneKg,
      'Текшерүү керек': item.checkKg,
      'Сатуу бирдиги': item.unitKg,
      'Минималдуу заказ': item.minOrderKg,
    },
    ru: {
      Бренд: item.brand,
      'Тип товара': item.typeRu,
      Назначение: item.purposeRu,
      'Область применения': item.areaRu,
      'Основа/состав': item.baseRu,
      'Вес/фасовка': item.packRu,
      'Внутренние/наружные работы': item.workZoneRu,
      'Что проверить': item.checkRu,
      'Единица продажи': item.unitRu,
      'Минимальный заказ': item.minOrderRu,
    },
  }
}

function makeStage14AConstructionCoreContent(item) {
  const specs = stage14ASpecs(item)

  return {
    titleKg: item.titleKg,
    titleRu: item.titleRu,
    shortDescriptionKg: item.shortKg,
    shortDescriptionRu: item.shortRu,
    fullDescriptionKg: item.fullKg,
    fullDescriptionRu: item.fullRu,
    specificationsKg: specs.kg,
    specificationsRu: specs.ru,
    applicationKg: item.applicationKg,
    applicationRu: item.applicationRu,
    benefitsKg: item.benefitsKg,
    benefitsRu: item.benefitsRu,
    instructionsKg: [...item.instructionsKg, ...stage14ACoreSafetyKg],
    instructionsRu: [...item.instructionsRu, ...stage14ACoreSafetyRu],
    faqKg: item.faqKg,
    faqRu: item.faqRu,
    seoTitleKg: `${item.titleKg} - StroyRayon`,
    seoTitleRu: `${item.titleRu} - StroyRayon`,
    seoDescriptionKg: item.seoKg,
    seoDescriptionRu: item.seoRu,
    aliasesKg: [item.titleKg, ...item.aliasesKg],
    aliasesRu: [item.titleRu, ...item.aliasesRu],
    aliases: item.aliases,
    imageStatus: 'needs-real-photo',
    relatedProductIds: item.relatedProductIds,
  }
}

